using Microsoft.Extensions.Logging;

namespace MyMauiApp;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureFonts(fonts =>
            {
                fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
            });

        // 1. Singleton — one HttpClient + DataService for the entire app lifetime.
        //    Avoids socket exhaustion and lets every consumer share cached
        //    auth tokens, base-URL config, etc.
        builder.Services.AddSingleton<HttpClient>(sp =>
        {
            return new HttpClient { BaseAddress = new Uri("https://api.example.com/") };
        });
        builder.Services.AddSingleton<IDataService, DataService>();

        // 2. Transient — a fresh ViewModel per request.
        //    ViewModels hold page-specific UI state that must not leak
        //    between navigations. Transient guarantees a clean instance
        //    every time a page is created or navigated to.
        builder.Services.AddTransient<MainViewModel>();
        builder.Services.AddTransient<DetailViewModel>();

        // 3. Transient — a fresh page per navigation.
        //    MAUI creates pages on each navigation push; transient
        //    matches that lifecycle and pairs each page with its own
        //    transient ViewModel via constructor injection.
        builder.Services.AddTransient<MainPage>();
        builder.Services.AddTransient<DetailPage>();

#if DEBUG
        builder.Logging.AddDebug();
#endif

        return builder.Build();
    }
}

